import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string: ");
        String input = scanner.nextLine();

        // Limit the input length to avoid buffer overflow
        if (input.length() > 10) {
            System.out.println("Input exceeds maximum allowed length. Please try again.");
            return;
        }

        char[] buffer = new char[10];

        // Copy user input into the buffer safely
        for (int i = 0; i < input.length() && i < buffer.length; i++) {
            buffer[i] = input.charAt(i);
        }

        System.out.println("Buffer content: " + new String(buffer));
    }
}

